const pollResponse = $('HTTP: Poll HeyGen Status').first().json;
const state = $('Wait: HeyGen Processing').first().json || $('Code: Extract HeyGen Video ID').first().json;

const statusRaw = pollResponse.data?.status || pollResponse.status || 'unknown';
const status = String(statusRaw).toLowerCase();
const pollCount = (state.pollCount || 0) + 1;
const maxPolls = state.maxPolls || 20;
const pollIntervalSec = state.pollIntervalSec || 30;

if (status === 'completed') {
  return [{
    json: {
      ...state,
      pollCount,
      heygenStatus: status,
      heygenRoute: 'completed'
    }
  }];
}

if (status === 'failed' || status === 'error' || status === 'canceled' || status === 'cancelled') {
  return [{
    json: {
      ...state,
      pollCount,
      heygenStatus: status,
      failStatus: 'Failed',
      failReason: `HeyGen status: ${status}`,
      heygenRoute: 'failed'
    }
  }];
}

if (pollCount >= maxPolls) {
  return [{
    json: {
      ...state,
      pollCount,
      heygenStatus: status,
      failStatus: 'Timed Out',
      failReason: `Timed out after ${pollCount} polls (~${pollCount * pollIntervalSec}s)`,
      heygenRoute: 'failed'
    }
  }];
}

return [{
  json: {
    ...state,
    pollCount,
    heygenStatus: status,
    heygenRoute: 'retry'
  }
}];

// Get day of year (1-365)
const now = new Date();
const start = new Date(now.getFullYear(), 0, 0);
const diff = now - start;
const oneDay = 1000 * 60 * 60 * 24;
const dayOfYear = Math.floor(diff / oneDay);

// Will use modulo with total workbook sections count in next node
return [{
  json: {
    dayOfYear: dayOfYear,
    date: now.toISOString().split('T')[0]
  }
}];

// Get day of year from earlier node
const dayOfYear = $('Code: Calculate Content Index').first().json.dayOfYear;
const date = $('Code: Calculate Content Index').first().json.date;

// Get all workbook sections from Google Sheets
const sections = $('Google Sheets: Get Workbook Content').all();
const totalSections = sections.length;

if (totalSections === 0) {
  throw new Error('Workbook Content is empty. Add at least one section before running the workflow.');
}

// Calculate which section to use today (day 1 should map to index 0)
const sectionIndex = (dayOfYear - 1) % totalSections;
const selectedSection = sections[sectionIndex].json;

return [{
  json: {
    date: date,
    dayOfYear: dayOfYear,
    sectionIndex: sectionIndex,
    totalSections: totalSections,
    rowId: selectedSection.row_id || selectedSection.row_number,
    sectionTitle: selectedSection.section_title,
    workbookContent: selectedSection.workbook_content,
    keyMessage: selectedSection.key_message
  }
}];

// Get section data from earlier
const sectionData = $('Code: Select Today\'s Section').first().json;

// Avatar IDs list
const avatarIds = [
  'f95484e160dd46d49bd3eff27a70efa0',
  'ecc28e92ccda43039065e010f6b745e7',
