];

// Select random avatar for background variation
const randomIndex = Math.floor(Math.random() * avatarIds.length);
const selectedAvatarId = avatarIds[randomIndex];

return [{
  json: {
    date: sectionData.date,
    rowId: sectionData.rowId,
    sectionTitle: sectionData.sectionTitle,
    workbookContent: sectionData.workbookContent,
    keyMessage: sectionData.keyMessage,
    avatarId: selectedAvatarId,
    avatarIndex: randomIndex
  }
}];

// Get the response from the generator node
const response = $('Generate Script').first().json;

// Recursive function to find the JSON string containing "script"
function findJsonRecursive(obj, depth = 0) {
    if (depth > 5) return null;
    if (obj === null || typeof obj !== 'object') return null;
    for (const key of Object.keys(obj)) {
        const val = obj[key];
        if (typeof val === 'string') {
            const trimmed = val.trim();
            if (trimmed.includes('"script"') || trimmed.indexOf("'script'") > -1) {
                return trimmed;
            }
        }
        if (typeof val === 'object') {
            const result = findJsonRecursive(val, depth + 1);
            if (result) return result;
        }
    }
    return null;
}

let content = response.message?.content || response.choices?.[0]?.message?.content;
if (typeof content !== 'string') content = null;

if (!content && Array.isArray(response.content) && response.content[0]?.text) {
    content = response.content[0].text;
}

if (!content) {
    content = findJsonRecursive(response);
}

if (!content && response.script) {
    content = JSON.stringify(response);
}

if (!content) {
    throw new Error('Could not find any string containing "script" in the response object. Please check the Input JSON. Structure: ' + JSON.stringify(response));
}

let parsed;
try {
  try {
    parsed = JSON.parse(content);
  } catch (e) {
    const jsonMatch = content.match(/\{[^{}]*"script"[^{}]*\}/) || content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    } else {
      throw e;
    }
  }
} catch (e) {
  throw new Error('Found content string but failed to parse JSON: ' + e.message + ' | Content: ' + content.substring(0, 100));
}

if (!parsed || !parsed.script) {
    if (parsed && typeof parsed === 'object' && !parsed.script) {
         throw new Error('Parsed JSON is missing "script" property. Result: ' + JSON.stringify(parsed));
    }
}

const combinedData = $('Code: Select Random Avatar & Combine Data').first().json;

return [{
  json: {
    date: combinedData.date,
    rowId: combinedData.rowId,
    sectionTitle: combinedData.sectionTitle,
    avatarId: combinedData.avatarId,
    script: parsed.script
  }
}];

// Get the created log record
const logRecord = $('Google Sheets: Create Production Log').first().json;
const contentData = $('Code: Parse AI Response').first().json;

return [{
  json: {
    logRowNumber: logRecord.row_number || logRecord.rowNumber,
    avatarId: contentData.avatarId,
    script: contentData.script,
    sectionTitle: contentData.sectionTitle
  }
}];

const heygenResponse = $('HTTP: HeyGen Generate Video').first().json;
const prepData = $('Code: Prepare HeyGen Request').first().json;

const videoId = heygenResponse.data?.video_id || heygenResponse.video_id;

if (!videoId) {
  throw new Error('No video_id returned from HeyGen: ' + JSON.stringify(heygenResponse));
}

return [{
  json: {
    logRowNumber: prepData.logRowNumber,
    heygenVideoId: videoId,
    pollCount: 0,
    maxPolls: 20,
    pollIntervalSec: 30
  }
}];

const pollResponse = $('HTTP: Poll HeyGen Status').first().json;
const current = $input.first().json;

const videoUrl = pollResponse.data?.video_url || pollResponse.video_url;

if (!videoUrl) {
  throw new Error('No video URL in HeyGen response: ' + JSON.stringify(pollResponse));
}

return [{
  json: {
    logRowNumber: current.logRowNumber,
    heygenVideoId: current.heygenVideoId,
    rawVideoUrl: videoUrl
  }
}];

const heygenData = $('Code: Extract HeyGen Video URL').first().json;

return [{
  json: {
    logRowNumber: heygenData.logRowNumber,
    finalVideoUrl: heygenData.rawVideoUrl
  }
}];

